import { SvgIconProps } from "../types";

export const SvgIcon = ({ src, width = "100%" }: SvgIconProps) => (
  <img
    src={`/img/svg/${src}`}
    alt={src}
    style={{
      width: width,
      maxWidth: "250px",
      height: "auto",
      display: "block",
      margin: "0 auto",
    }}
  />
);